{
  "title": "Mastering Character Drawing: From Concept to Creation",
  "description": "This course is designed for intermediate artists who want to enhance their skills in drawing specific characters, focusing on the provided images. The course will cover techniques, styles, and tips to create appealing mascot characters.",
  "modules": [
    {
      "id": "module_1",
      "title": "Understanding Character Design",
      "description": "Explore the fundamentals of character design, including anatomy, proportions, and personality traits. Analyze the provided images to identify key features and styles."
    },
    {
      "id": "module_2",
      "title": "Sketching Techniques for Mascots",
      "description": "Learn various sketching techniques to capture the essence of the characters. Focus on dynamic poses, expressions, and the unique characteristics of mascots."
    },
    {
      "id": "module_3",
      "title": "Adding Color and Texture",
      "description": "Discover how to effectively use color and texture to bring your characters to life. Experiment with different coloring techniques that suit mascot designs."
    },
    {
      "id": "module_4",
      "title": "Finalizing Your Character Art",
      "description": "Learn how to refine your drawings and prepare them for presentation. This module will cover digital tools and techniques for polishing your mascot art."
    }
  ]
}
